// ❌ Nomes vagos — o que é "d"? O que "Item" renderiza?
const d = new Date();
function Item({ x }) {
  return <div>{x}</div>;
}

// ✅ Nomes descritivos — intenção clara
const createdAt = new Date();
function ProductCard({ product }) {
  return (
    <div>
      <h3>{product.name}</h3>
      <p>{product.price}</p>
    </div>
  );
}

// ❌ Componente "god" — faz tudo numa função só
function UserProfile({ user }) {
  return (
    <div>
      <img src={user.avatar} alt={user.name} />
      <h2>{user.name}</h2>
      <p>{user.bio}</p>
      <ul>
        {user.posts.map(post => (
          <li key={post.id}>
            <h3>{post.title}</h3>
            <p>{post.excerpt}</p>
          </li>
        ))}
      </ul>
    </div>
  );
}

// ✅ Responsabilidades separadas
function UserAvatar({ src, name }) {
  return <img src={src} alt={name} />;
}

function PostItem({ post }) {
  return (
    <li>
      <h3>{post.title}</h3>
      <p>{post.excerpt}</p>
    </li>
  );
}

function UserProfile({ user }) {
  return (
    <div>
      <UserAvatar src={user.avatar} name={user.name} />
      <h2>{user.name}</h2>
      <p>{user.bio}</p>
      <ul>
        {user.posts.map(post => (
          <PostItem key={post.id} post={post} />
        ))}
      </ul>
    </div>
  );
}

// ❌ Indentação profunda — difícil de seguir
function Dashboard({ user, isLoading, error }) {
  if (!error) {
    if (!isLoading) {
      if (user) {
        return <UserDashboard user={user} />;
      } else {
        return <p>Usuário não encontrado</p>;
      }
    } else {
      return <Spinner />;
    }
  } else {
    return <ErrorMessage error={error} />;
  }
}

// ✅ Early returns — fluxo linear
function Dashboard({ user, isLoading, error }) {
  if (error) return <ErrorMessage error={error} />;
  if (isLoading) return <Spinner />;
  if (!user) return <p>Usuário não encontrado</p>;

  return <UserDashboard user={user} />;
}
